    <OutputType>Exe</OutputType>
  </PropertyGroup>
</Project>""")
    with open(os.path.join(d, "Program.cs"), "w") as f:
        f.write(code)
    r = subprocess.run(["dotnet", "run", "--project", d], capture_output=True, text=True, timeout=60)
    print(r.stdout[:3000])
