using System.ComponentModel;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Build the AI client ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define tools ---
var notebook = new Notebook();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        WebSearch.SearchAsync,
        name: "web_search",
        description: "Searches the web for a query and returns relevant snippets."),
    AIFunctionFactory.Create(
        notebook.AddNote,
        name: "add_note",
        description: "Saves a research note with a title and body for later summarization."),
    AIFunctionFactory.Create(
        notebook.GetNotes,
        name: "get_notes",
        description: "Returns all saved research notes as a numbered list."),
};

// --- Create agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your goal is to thoroughly research the given topic
        using the web_search tool, take organized notes using the add_note tool,
        and then produce a comprehensive summary.

        Workflow:
        1. Search for the topic from multiple angles using web_search (at least 3 different queries).
        2. For each search, extract key findings and save them as notes using add_note.
        3. When you have gathered enough information, call get_notes to review everything.
        4. Produce a final, well-structured summary with sections, key facts, and sources.

        Be thorough but concise. Focus on factual, verifiable information.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

// --- Run the agent ---
var session = await agent.CreateSessionAsync("research-session");

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions);

Console.WriteLine(response.Text);
Console.WriteLine($"\n--- Research Complete ---");
Console.WriteLine($"📝 {notebook.Count} note(s) were taken during research.\n");

// ============================================================
// Helper
// ============================================================

static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var topic = Console.ReadLine()?.Trim();
    return string.IsNullOrWhiteSpace(topic)
        ? throw new InvalidOperationException("A research topic is required.")
        : topic;
}

// ============================================================
// Web search tool — uses DuckDuckGo HTML (no API key needed)
// ============================================================

static partial class WebSearch
{
    private static readonly HttpClient s_http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0 (compatible)" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    public static async Task<string> SearchAsync(
        [Description("The search query to look up")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");
        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await s_http.GetStringAsync(url, cancellationToken);

            var results = ParseResults(html);
            return results.Count > 0
                ? string.Join("\n\n", results)
                : "No results found for this query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static List<string> ParseResults(string html)
    {
        var results = new List<string>();

        // Extract result titles and snippets from DuckDuckGo HTML results
        var snippetMatches = SnippetRegex().Matches(html);
        var titleMatches = TitleRegex().Matches(html);

        var count = Math.Min(snippetMatches.Count, 5);
        for (var i = 0; i < count; i++)
        {
            var snippet = StripHtml(snippetMatches[i].Groups[1].Value).Trim();
            var title = i < titleMatches.Count
                ? StripHtml(titleMatches[i].Groups[1].Value).Trim()
                : $"Result {i + 1}";

            if (!string.IsNullOrWhiteSpace(snippet))
            {
                results.Add($"**{title}**\n{snippet}");
            }
        }

        // Fallback: extract any <a> + text blocks if the above yielded nothing
        if (results.Count == 0)
        {
            foreach (Match m in FallbackRegex().Matches(html).Cast<Match>().Take(5))
            {
                var text = StripHtml(m.Groups[1].Value).Trim();
                if (text.Length > 40)
                    results.Add(text);
            }
        }

        return results;
    }

    private static string StripHtml(string html)
    {
        var text = HtmlTagRegex().Replace(html, " ");
        text = System.Net.WebUtility.HtmlDecode(text);
        return WhitespaceRegex().Replace(text, " ").Trim();
    }

    [GeneratedRegex("""class="result__snippet"[^>]*>(.*?)</""", RegexOptions.Singleline)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex("""class="result__a"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
    private static partial Regex TitleRegex();

    [GeneratedRegex("""<a[^>]+class="[^"]*result[^"]*"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
    private static partial Regex FallbackRegex();

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex HtmlTagRegex();

    [GeneratedRegex(@"\s+")]
    private static partial Regex WhitespaceRegex();
}

// ============================================================
// Note-taking tool — in-memory notebook
// ============================================================

sealed class Notebook
{
    private readonly List<(string Title, string Body)> _notes = [];

    public int Count => _notes.Count;

    public string AddNote(
        [Description("Short title for the note")] string title,
        [Description("The note content / key findings")] string body)
    {
        _notes.Add((title, body));
        Console.WriteLine($"  📝 Note added: \"{title}\"");
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"Note #{i + 1}: {n.Title}\n{n.Body}"));
    }
}

