var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Build the AI client ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define tools ---
var notebook = new Notebook();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        WebSearch.SearchAsync,
        name: "web_search",
        description: "Searches the web for a query and returns relevant snippets."),
    AIFunctionFactory.Create(
        notebook.AddNote,
        name: "add_note",
        description: "Saves a research note with a title and body for later summarization."),
    AIFunctionFactory.Create(
        notebook.GetNotes,
        name: "get_notes",
        description: "Returns all saved research notes as a numbered list."),
};

// --- Create agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your goal is to thoroughly research the given topic
        using the web_search tool, take organized notes using the add_note tool,
        and then produce a comprehensive summary.

        Workflow:
        1. Search for the topic from multiple angles using web_search (at least 3 different queries).
        2. For each search, extract key findings and save them as notes using add_note.
        3. When you have gathered enough information, call get_notes to review everything.
        4. Produce a final, well-structured summary with sections, key facts, and sources.

        Be thorough but concise. Focus on factual, verifiable information.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

// --- Run the agent ---
var session = await agent.CreateSessionAsync("research-session");

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
